// Extraer datos del body del webhook
const body = $input.first().json.body || $input.first().json;

const companySlug = body.company_slug || 'default';
const filename = body.filename || 'document.pdf';
const category = body.category || 'general';
const fileBase64 = body.file || '';

// Limpiar el base64 (quitar data:... prefix si existe)
let cleanBase64 = fileBase64;
if (cleanBase64.includes(',')) {
  cleanBase64 = cleanBase64.split(',')[1];
}

// Crear nombre de colección
const collectionName = 'company_' + companySlug.replace(/[^a-z0-9_-]/gi, '_').toLowerCase() + '_knowledge';

// Determinar mime type basado en extensión
let mimeType = 'application/pdf';
const ext = filename.toLowerCase().split('.').pop();
if (ext === 'txt') mimeType = 'text/plain';
else if (ext === 'doc' || ext === 'docx') mimeType = 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';
else if (ext === 'csv') mimeType = 'text/csv';
else if (ext === 'json') mimeType = 'application/json';
else if (ext === 'md') mimeType = 'text/markdown';

// Convertir base64 a Buffer
const fileBuffer = Buffer.from(cleanBase64, 'base64');

// Retornar JSON con el archivo como binario
return {
  json: {
    company_slug: companySlug,
    filename: filename,
    category: category,
    collection_name: collectionName,
    mime_type: mimeType
  },
  binary: {
    data: {
      data: fileBuffer.toString('base64'),
      mimeType: mimeType,
      fileName: filename
    }
  }
};
